import React, { useState, useContext } from 'react';
import { useNavigate } from 'react-router-dom';
import { AuthContext } from '../../context/AuthContext';

const Login = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const { login } = useContext(AuthContext);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    try {
      const user = await login(email, password);
      if (user.isAdmin) {
        navigate('/');
      } else {
        setError('Not authorized as admin');
      }
    } catch (err) {
      setError(err);
    }
  };

  return (
    <div className="min-h-screen bg-gray-light flex items-center justify-center font-sans text-black">
      <div className="bg-white p-10 rounded-lg shadow-sm border border-border w-full max-w-md">
        <h1 className="text-3xl font-serif text-center mb-8 font-bold">Admin Login</h1>

        {error && (
          <div className="bg-red-50 text-red-600 p-3 rounded mb-6 text-sm border border-red-200">
            {error}
          </div>
        )}

        <form onSubmit={handleSubmit} className="space-y-6">
          <div>
            <label className="block text-sm font-medium mb-2">Email</label>
            <input
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
              className="w-full p-3 border border-border rounded focus:outline-none focus:border-black transition-colors"
              placeholder="admin@daftk.com"
            />
          </div>
          <div>
            <label className="block text-sm font-medium mb-2">Password</label>
            <input
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
              className="w-full p-3 border border-border rounded focus:outline-none focus:border-black transition-colors"
              placeholder="••••••••"
            />
          </div>
          <button
            type="submit"
            className="w-full bg-black text-white p-3 rounded uppercase tracking-wider font-medium hover:bg-gray-dark transition-colors"
          >
            Sign In
          </button>
        </form>
      </div>
    </div>
  );
};

export default Login;
